import React, { useState } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import {  faBars, faXmark } from '@fortawesome/free-solid-svg-icons';
//import '../Navbar.css';
import cls from '../Navbar.module.scss';
import { Link } from 'react-router-dom';
import { isMobile } from 'react-device-detect';
import { FLOWHERO } from '../../../../shared/utility';

function Navbar() {
	const [nav, setNav] = useState(false);
	const [isButtonDisabled, setIsButtonDisabled] = useState(false);

	const openNav = () => {
		setNav(!nav);
	};

	return (
		<div className={cls.navbarsection} style={{backgroundColors:'yellow', height: isMobile ? '100px' : '160px' }}>
			<div className={cls.navbartitle} style={{ fontSize: isMobile ? '20px' : '26px', marginLeft: isMobile ? '0' : '50px' }}>
				{FLOWHERO(isMobile ? '26px':'36px')}
			</div>
			{/* Desktop */}
			<ul className={cls.navbaritems} style={{display: isMobile ? 'none':''}}>
				<li>
					<Link to="/" className={cls.navbarlinks}>
						{`HOME`}
					</Link>
				</li>

				<li>
					<a
						className={cls.navbarlinks}
						style={{ cursor: 'pointer' }}
						onClick={() => {
							window.scrollTo({ top: 4000, behavior: 'smooth' });
						}}
					>
						{'PRICING'}
					</a>
				</li>

				<li>
					<a href="#/login" className={cls.navbarlinks}>
						{`LOGIN`}
					</a>
				</li>
				<li>
					<a href="#/register" className={cls.navbarlinks}>
						{`REGISTER`}
					</a>
				</li>
			</ul>

			{/* Mobile */}
			<div className={`mobile-navbar ${nav ? 'open-nav' : ''}`}>
				<div onClick={openNav} className="mobile-navbar-close">
					<FontAwesomeIcon icon={faXmark} className="hamb-icon" />
				</div>

				<ul className={cls.mobilenavbarlinks}>
					<li>
						<Link onClick={openNav} to="/">
							{`HOME`}
						</Link>
					</li>

					<li>
						<a onClick={openNav} href="/#/login">
							{`LOGIN`}
						</a>
					</li>
					<li>
						<a onClick={openNav} href="/">
							{`REGISTER`}
						</a>
					</li>
				</ul>
			</div>

			{/* Hamburger Icon */}
			<div className="mobile-nav" style={{ display: isMobile ? 'block' : 'none' }}>
				<FontAwesomeIcon icon={faBars} onClick={openNav} className="hamb-icon" />
			</div>
		</div>
	);
}

export default Navbar;



